string reverseWords(const string &s) {
    istringstream iss(s); // split by whitespace
    vector<string> words;
    string word;

    while (iss >> word) { // automatically skips multiple spaces
        words.push_back(word);
    }

    reverse(words.begin(), words.end());

    string res;
    for (size_t i = 0; i < words.size(); i++) {
        res += words[i];
        if (i != words.size() - 1) res += " ";
    }

    return res;
}

