void reverseWords(char *line) {
    // remove trailing newline
    int len = strlen(line);
    if (len > 0 && line[len - 1] == '\n')
        line[len - 1] = '\0';

    char *words[MAX_WORDS];
    int count = 0;

    // split by spaces/tabs
    char *token = strtok(line, " \t");
    while (token != NULL) {
        words[count++] = token;
        token = strtok(NULL, " \t");
    }

    // print reversed words
    for (int i = count - 1; i >= 0; i--) {
        printf("%s", words[i]);
        if (i > 0) printf(" ");
    }
    printf("\n");
}

