public static String reverseWords(String s) {
       // Trim leading/trailing spaces
       s = s.trim();

       // Split words by one or more spaces
       String[] words = s.split("\\s+");

       // Reverse order
       StringBuilder sb = new StringBuilder();
       for (int i = words.length - 1; i >= 0; i--) {
           sb.append(words[i]);
           if (i > 0) sb.append(" ");
       }

       return sb.toString();
   }

