function reverseWords(s) {
    let n = s.length;
    let i = 0;
    const words = [];

    // Skip leading spaces
    while (i < n && s[i] === ' ') i++;

    while (i < n) {
        let word = '';

        // Collect a word
        while (i < n && s[i] !== ' ') {
            word += s[i];
            i++;
        }

        if (word.length > 0) words.push(word);

        // Skip spaces between words
        while (i < n && s[i] === ' ') i++;
    }

    // Join words in reverse order
    let result = '';
    for (let j = words.length - 1; j >= 0; j--) {
        result += words[j];
        if (j !== 0) result += ' ';
    }

    return result;
}
